// ============================================
// PATCH #1: INIT & ACL - ORCHESTRATOR SUPPORT
// ============================================
// Pour: WF4 Quantitative & WF2 Graph
// Bug: Workflows échouent quand appelés par orchestrateur
// Fix: Support multi-format d'entrée

// Init & ACL for RAG - HARDENED V2.2 (ORCHESTRATOR FIX)
const rawInput = $input.first().json;
const input = rawInput.body || rawInput;

// === EXTRACTION ROBUSTE DE LA QUERY ===
// Supporte: webhook, chat trigger, sub-workflow, ET orchestrator
let queryStr = '';

// Priorité 1: Direct query field (webhook/chat)
if (typeof input.query === 'string') {
  queryStr = input.query;
}
// Priorité 2: Chat input
else if (input.chatInput) {
  queryStr = input.chatInput;
}
// Priorité 3: Orchestrator format - task_query
else if (input.task_query) {
  queryStr = input.task_query;
}
// Priorité 4: Orchestrator format - current_task.query
else if (input.current_task && typeof input.current_task.query === 'string') {
  queryStr = input.current_task.query;
}
// Priorité 5: Query as object (stringify)
else if (input.query && typeof input.query === 'object') {
  queryStr = JSON.stringify(input.query);
}

const query = queryStr.trim();

// === VALIDATION ===
if (!query || query.length < 2) {
  throw new Error('VALIDATION_ERROR: query is required and must be at least 2 characters');
}

// === EXTRACTION DU USER CONTEXT ===
// Parse user_context (peut être string JSON ou objet)
let userContext = {};

if (typeof input.user_context === 'string') {
  try {
    userContext = JSON.parse(input.user_context);
  } catch (e) {
    userContext = {};
  }
} else if (input.user_context && typeof input.user_context === 'object') {
  userContext = input.user_context;
}

// === EXTRACTION DU TRACE_ID ===
// Support multiple sources
const traceId = input.trace_id || 
                input.current_task?.trace_id || 
                `tr-rag-${Date.now()}-${Math.random().toString(36).substring(2, 10)}`;

// === OUTPUT ===
return [{
  json: {
    trace_id: traceId,
    query: query.substring(0, 2000),
    user_context: {
      tenant_id: userContext.tenant_id || input.tenant_id || 'default',
      groups: Array.isArray(userContext.groups) ? userContext.groups : ['guest']
    },
    timestamp: new Date().toISOString(),
    source: rawInput.body ? 'webhook' : 
            (rawInput.chatInput ? 'chat' : 
            (input.task_query ? 'orchestrator' : 'subworkflow')),

    // Metadata pour debugging
    _debug: {
      original_input_keys: Object.keys(input),
      query_source: input.task_query ? 'task_query' : 
                    (input.current_task ? 'current_task.query' : 
                    (input.chatInput ? 'chatInput' : 'query'))
    }
  }
}];

// Build schema context for LLM
const inputData = $input.all();
if (!inputData || inputData.length === 0) {
  return {
    ...$node['Init & ACL'].json,
    schema_context: "Aucune table trouvée dans le schéma public.",
    available_tables: []
  };
}

const schemaData = inputData.map(i => i.json);
const tables = {};

schemaData.forEach(col => {
  if (!tables[col.table_name]) tables[col.table_name] = [];
  tables[col.table_name].push(`${col.column_name} ${col.data_type}${col.is_nullable === 'NO' ? ' NOT NULL' : ''}`);
});

const schemaContext = Object.entries(tables)
  .map(([table, columns]) => `Table: ${table}\nColumns: ${columns.join(', ')}`)
  .join('\n\n');

// Add common relationships / foreign keys context
const FK_CONTEXT = `
FOREIGN KEY RELATIONSHIPS (for JOINs):
- financials.company_name = balance_sheet.company_name (join on company + year + period)
- financials.company_name = quarterly_revenue.company_name
- financials.company_name = employees.company_name
- orders.customer_id = customers.id
- orders.product_id = products.id
- order_items.order_id = orders.id
- order_items.product_id = products.id
- employees.department_id = departments.id

IMPORTANT RULES:
- financials: use period='FY' for annual totals (avoid double-counting with quarterly rows)
- tenant_id filter: WHERE tenant_id = 'default' OR tenant_id IS NULL (catches all data)
- Company names may have suffixes (Inc, Corp, Ltd) — use ILIKE '%company_name%'
`;

const initData = $node['Init & ACL'].json;

return {
  ...initData,
  schema_context: schemaContext,
  available_tables: Object.keys(tables)
};

// CRITICAL: SQL Validator - Security Shield (ERROR-SAFE VERSION + TEMPLATE SUPPORT)
// Never throws - returns error data that flows through pipeline
const contextData = $node['Schema Context Builder'].json;

try {
  // ============================================
  // TEMPLATE CHECK — bypass LLM response parsing if template matched
  // ============================================
  const prepareNode = $node['Prepare SQL Request'].json;
  if (prepareNode && prepareNode.template_matched === true) {
    const templateSql = prepareNode.template_sql;
    // Basic validation of template SQL
    if (templateSql && templateSql.toUpperCase().startsWith('SELECT')) {
      return {
        ...contextData,
        validated_sql: templateSql,
        explanation: prepareNode.template_explanation || 'Template-matched query',
        validation_status: 'PASSED',
        validation_method: 'TEMPLATE',
        validation_timestamp: new Date().toISOString()
      };
    }
  }

  // ============================================
  // NORMAL PATH — parse LLM response
  // ============================================
  let llmResponse = {};
  try {
    // Check if LLM returned an error instead of completions
    if ($json.error) {
      return {
        ...contextData,
        validated_sql: "SELECT 'LLM_RATE_LIMITED: " + String($json.error.message || JSON.stringify($json.error)).replace(/'/g, "").substring(0, 100) + "' as error_message, 'error' as status LIMIT 1",
        explanation: 'LLM returned error: ' + JSON.stringify($json.error).substring(0, 200),
        validation_status: 'FAILED',
        validation_error: 'LLM_ERROR',
        validation_timestamp: new Date().toISOString()
      };
    }
    let rawContent = $json.choices?.[0]?.message?.content || '{}';
    // Strip markdown code fences if present (e.g. ```json ... ```)
    rawContent = rawContent.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
    llmResponse = JSON.parse(rawContent || '{}');
  } catch (e) {
    // LLM returned invalid JSON - return safe fallback
    return {
      ...contextData,
      validated_sql: "SELECT 'SQL_GENERATION_ERROR: Invalid LLM response' as error_message, 'error' as status LIMIT 1",
      explanation: 'LLM returned invalid JSON response',
      validation_status: 'FAILED',
      validation_error: 'SQL_GENERATION_ERROR',
      validation_timestamp: new Date().toISOString()
    };
  }

  const sql = String(llmResponse.sql || '').trim();
  const sqlUpper = sql.toUpperCase();

  // FORBIDDEN PATTERNS - P0 Security
  const forbiddenPatterns = [
    /DELETE|UPDATE|INSERT|DROP|TRUNCATE|ALTER|CREATE/i,
    /GRANT|REVOKE|EXEC|EXECUTE|CALL/i,
    /--|;.*;|UNION.*SELECT/i,
    /xp_|sp_|pg_sleep/i,
    /\bINTO\s+OUTFILE\b|\bLOAD_FILE\b/i
  ];

  for (const pattern of forbiddenPatterns) {
    if (pattern.test(sqlUpper)) {
      return {
        ...contextData,
        validated_sql: "SELECT 'SQL_INJECTION_DETECTED' as error_message, 'error' as status LIMIT 1",
        explanation: 'Forbidden SQL pattern detected',
        validation_status: 'FAILED',
        validation_error: 'SQL_INJECTION_DETECTED',
        validation_timestamp: new Date().toISOString()
      };
    }
  }

  // REQUIRED PATTERNS - return error instead of throwing
  if (!sqlUpper.startsWith('SELECT')) {
    return {
      ...contextData,
      validated_sql: "SELECT 'Query must start with SELECT' as error_message, 'error' as status LIMIT 1",
      explanation: 'Query must start with SELECT',
      validation_status: 'FAILED',
      validation_error: 'SQL_VALIDATION_ERROR',
      validation_timestamp: new Date().toISOString()
    };
  }

  // Add LIMIT if missing (instead of throwing)
  let finalSql = llmResponse.sql;
  if (!sqlUpper.includes('LIMIT')) {
    finalSql = finalSql + ' LIMIT 1000';
  }

  // Extract LIMIT value
  const limitMatch = sqlUpper.match(/LIMIT\s+(\d+)/i);
  if (limitMatch) {
    const limitValue = parseInt(limitMatch[1]);
    if (limitValue > 1000) {
      finalSql = finalSql.replace(/LIMIT\s+\d+/i, 'LIMIT 1000');
    }
  }

  // Check tenant_id filter - add if missing (instead of throwing)
  if (!sqlUpper.includes('TENANT_ID')) {
    // Try to add tenant_id filter
    if (sqlUpper.includes('WHERE')) {
      finalSql = finalSql.replace(/WHERE/i, `WHERE tenant_id = '${contextData.user_context.tenant_id}' AND`);
    } else if (sqlUpper.includes('FROM')) {
      // Skip tenant_id injection for complex queries (JOINs) - LLM handles it via prompt
    }
  }

  // Passed validation
  return {
    ...contextData,
    validated_sql: finalSql,
    explanation: llmResponse.explanation || '',
    validation_status: 'PASSED',
    validation_method: 'LLM',
    validation_timestamp: new Date().toISOString()
  };

} catch (globalError) {
  // Catch-all: never let the node crash
  return {
    ...contextData,
    validated_sql: "SELECT 'VALIDATOR_ERROR: " + String(globalError.message).replace(/'/g, "''").substring(0, 100) + "' as error_message, 'error' as status LIMIT 1",
    explanation: 'Validator encountered an unexpected error: ' + globalError.message,
    validation_status: 'FAILED',
    validation_error: 'VALIDATOR_CRASH',
    validation_timestamp: new Date().toISOString()
  };
}

// Prepare data for interpretation - handles both success and error from SQL Executor
let validatorData = {};
try {
  validatorData = $node['SQL Validator (Shield #1)'].json || {};
} catch (e) {
  validatorData = {};
}

const inputItems = $input.all();
const sqlResults = [];

for (const item of inputItems) {
  // Check if this is an error item
  if (item.json && !item.json.error && !item.json.errorMessage) {
    sqlResults.push(item.json);
  }
}

if (sqlResults.length === 0) {
  return {
    ...validatorData,
    sql_results: [],
    result_count: 0,
    has_results: false,
    null_aggregation: false
  };
}

// ISSUE-QT-14: Detect null aggregation results (SUM/AVG/COUNT returning null)
// This happens when WHERE filters match no rows (e.g., company_name = 'TechVision'
// when DB has 'TechVision Inc') - query succeeds but all aggregates return null.
const validatedSql = (validatorData.validated_sql || '').toUpperCase();
const isAggregation = /\b(SUM|AVG|COUNT|MIN|MAX)\s*\(/.test(validatedSql);

if (isAggregation && sqlResults.length > 0) {
  const allAggNull = sqlResults.every(row => {
    const vals = Object.values(row);
    return vals.length > 0 && vals.every(v => v === null || v === undefined);
  });
  if (allAggNull) {
    return {
      ...validatorData,
      sql_results: sqlResults,
      result_count: 0,
      has_results: false,
      null_aggregation: true,
      result_preview: 'WARNING: Aggregation query returned null on all columns. Probable cause: WHERE filter with inexact entity name. No rows matched the filter.'
    };
  }
}

return {
  ...validatorData,
  sql_results: sqlResults,
  result_count: sqlResults.length,
  has_results: true,
  null_aggregation: false,
  result_preview: JSON.stringify(sqlResults.slice(0, 5), null, 2)
};

// Response Formatter - handles both success and error paths
// May receive data from Interpretation Layer (success) or Needs SQL Repair? (error)
let aggregatorData = {};
let initData = {};
let interpretation = '';

// Try to get Init & ACL data (always available)
try {
  initData = $node['Init & ACL'].json || {};
} catch (e) {
  initData = {};
}

// Try to get Result Aggregator data (only on success path)
try {
  aggregatorData = $node['Result Aggregator'].json || {};
} catch (e) {
  aggregatorData = {};
}

// Determine interpretation based on input source
// On success path: $json comes from Interpretation Layer (has choices)
// On error path: $json comes from Needs SQL Repair? (has error/fallback_message)
if ($json.choices?.[0]?.message?.content) {
  interpretation = $json.choices[0].message.content;
} else if ($json.error || $json.fallback_message) {
  // Coming from error path
  interpretation = $json.fallback_message || 'Unable to generate SQL query for this question. Error: ' + (typeof $json.error === 'object' ? JSON.stringify($json.error) : ($json.error || 'unknown'));
} else {
  interpretation = 'No interpretation available';
}

return {
  // ISSUE-QT-14: detect null aggregation - mark as NULL_RESULT not SUCCESS
  status: aggregatorData.null_aggregation ? 'NULL_RESULT' : (aggregatorData.validation_status === 'PASSED' ? 'SUCCESS' : 'ERROR'),
  trace_id: aggregatorData.trace_id || initData.trace_id || '',
  query: aggregatorData.query || initData.query || '',
  sql_executed: aggregatorData.validated_sql || '',
  result_count: aggregatorData.result_count || 0,
  interpretation: interpretation,
  raw_results: aggregatorData.has_results ? (aggregatorData.sql_results || []) : [],
  null_aggregation: aggregatorData.null_aggregation || false,
  metadata: {
    validation_status: aggregatorData.null_aggregation ? 'NULL_AGGREGATION' : (aggregatorData.validation_status || 'UNKNOWN'),
    timestamp: new Date().toISOString(),
    engine: 'QUANTITATIVE'
  }
};

// Error handler - graceful fallback when nodes haven't executed
try {
  const error = $json;
  let initData = {};
  try {
    initData = $node['Init & ACL']?.json || {};
  } catch (e) {
    initData = { trace_id: 'err-' + Date.now(), query: 'unknown' };
  }

  return {
    status: 'ERROR',
    trace_id: initData.trace_id || 'err-' + Date.now(),
    error_type: error.message?.includes('SQL_') ? 'SQL_ERROR' :
                error.message?.includes('rate') ? 'RATE_LIMIT' :
                error.message?.includes('Provider') ? 'PROVIDER_ERROR' : 'SYSTEM_ERROR',
    error_message: error.message || error.description || 'Unknown error',
    query: initData.query || 'unknown',
    timestamp: new Date().toISOString()
  };
} catch (e) {
  return {
    status: 'ERROR',
    trace_id: 'err-fallback-' + Date.now(),
    error_type: 'ERROR_HANDLER_FAILURE',
    error_message: e.message || 'Error handler itself failed',
    timestamp: new Date().toISOString()
  };
}

// SQL Error Handler - Self-Healing (MAX 2 REPAIRS)
// Counter via $execution.id key + $getWorkflowStaticData (requires N8N_RUNNERS_ENABLED=false)
const MAX_REPAIRS = 2;

const staticData = $getWorkflowStaticData('global');
const execId = ($execution && $execution.id) ? $execution.id : ('fallback_' + Date.now());
const retryKey = 'repair_' + execId;

const currentCount = (staticData[retryKey] || 0) + 1;
staticData[retryKey] = currentCount;

if (currentCount > MAX_REPAIRS) {
  delete staticData[retryKey];
  return [{ json: { needs_repair: false, retry_exhausted: true, error_type: 'SQL_MAX_RETRIES', attempts: currentCount } }];
}

let originalQuery = 'unknown';
let failedSQL = '';
let errorMsg = 'SQL execution failed';
let schemaContext = '';
let tenantId = 'default';

try { originalQuery = $node['Init & ACL'].json.query; } catch(e) {}
try { failedSQL = ($node['SQL Validator (Shield #1)'].json || {}).validated_sql || $json.sql || ''; } catch(e) {}
try { errorMsg = $json.error_message || $json.message || 'SQL execution failed'; } catch(e) {}
try { schemaContext = $node['Schema Context Builder'].json.schema_context; } catch(e) {}
try { tenantId = ($node['Init & ACL'].json.user_context || {}).tenant_id || 'default'; } catch(e) {}

return [{
  json: {
    needs_repair: true,
    retry_count: currentCount,
    original_query: originalQuery,
    failed_sql: failedSQL,
    error_message: errorMsg,
    schema_context: schemaContext,
    tenant_id: tenantId,
    repair_context: {
      failed_sql: failedSQL,
      error_message: errorMsg,
      schema_context: schemaContext
    }
  }
}];

// Parse SQL Repair response and prepare for retry
const repairResponse = $json;
let repairedSql = '';

try {
  const content = repairResponse.choices?.[0]?.message?.content || repairResponse.body?.choices?.[0]?.message?.content;
  // Strip markdown code fences if present
  const cleanContent = (content || '').replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  const parsed = JSON.parse(cleanContent || '{}');
  repairedSql = parsed.sql;
} catch (e) {
  // If parsing fails, return error
  return {
    success: false,
    error: 'SQL_REPAIR_PARSE_ERROR',
    raw_response: repairResponse
  };
}

// Prepare for SQL Validator re-run
return {
  sql: repairedSql,
  is_repaired: true,
  repair_iteration: $node['SQL Error Handler (Self-Healing)'].json.retry_count
};

// Prepare SQL Request - Safe JSON Building + SQL Templates + Sample Data
const initData = $node['Schema Context Builder'].json;

// ============================================
// SQL Template matching — bypass LLM for simple queries
// ============================================
const query = initData.query.toLowerCase();
const companies = {'techvision': 'TechVision Inc', 'greenenergy': 'GreenEnergy Corp', 'healthplus': 'HealthPlus Labs'};
let company = null;
for (const [key, name] of Object.entries(companies)) {
  if (query.includes(key.toLowerCase())) { company = name; break; }
}
const yearMatch = query.match(/(?:fy\s*)?(\d{4})/);
const year = yearMatch ? parseInt(yearMatch[1]) : null;
const quarterMatch = query.match(/q([1-4])\b/i);
const quarter = quarterMatch ? `Q${quarterMatch[1]}` : null;
const metricMap = {
  'revenue': 'revenue', 'net income': 'net_income', 'gross profit': 'gross_profit',
  'operating income': 'operating_income', 'r&d': 'research_development',
  'research': 'research_development', 'eps': 'diluted_eps', 'diluted eps': 'diluted_eps',
  'basic eps': 'basic_eps', 'operating expenses': 'operating_expenses',
  'cost of goods': 'cost_of_goods_sold', 'selling': 'selling_general_admin'
};
let metric = null;
for (const [keyword, col] of Object.entries(metricMap)) {
  if (query.includes(keyword)) { metric = col; break; }
}
if (company && year && metric) {
  const period = quarter || 'FY';
  const templateSql = `SELECT ${metric} FROM financials WHERE company_name = '${company}' AND fiscal_year = ${year} AND period = '${period}' LIMIT 1`;
  // Return BOTH: a minimal requestBody (so HTTP node doesn't crash) AND the template result
  return [{json: {
    requestBody: {
      model: 'meta-llama/llama-3.3-70b-instruct:free',
      messages: [{role: 'user', content: 'Say OK'}],
      temperature: 0, max_tokens: 5
    },
    template_matched: true,
    template_sql: templateSql,
    template_explanation: `Template: ${metric} of ${company} in ${period} ${year}`,
    template_confidence: 0.95
  }}];
}

// ============================================
// LLM-based SQL generation (for complex queries)
// ============================================
const requestBody = {
  model: 'meta-llama/llama-3.3-70b-instruct:free',
  messages: [
    {
      role: "system",
      content: `You are an expert SQL generator with explicit Chain-of-Thought reasoning.

!!!! CRITICAL DATA MODEL WARNING !!!!
The financials table contains BOTH quarterly rows (period='Q1','Q2','Q3','Q4') AND a full-year aggregate row (period='FY') for each company/year.
- For annual totals: ALWAYS use period = 'FY'. NEVER SUM() without period filter or you get DOUBLE the real value.
- For quarterly data: filter by the specific quarter (period = 'Q1', etc.).
- SUM() is only valid across different companies or fiscal_years, NOT across periods within the same company/year.

SAMPLE DATA (financials table):
  company_name='TechVision Inc', fiscal_year=2023, period='FY', revenue=6745000000, net_income=1616600000, diluted_eps=16.17
  company_name='GreenEnergy Corp', fiscal_year=2023, period='FY', revenue=3650000000, net_income=730000000
  company_name='HealthPlus Labs', fiscal_year=2023, period='FY', revenue=1152000000, net_income=288000000
  company_name='TechVision Inc', fiscal_year=2023, period='Q1', revenue=1552350000

=== 4-STEP METHOD ===

STEP 1 - UNDERSTAND THE QUESTION:
- Identify ENTITIES mentioned (probable tables)
- Identify METRICS requested (SUM, COUNT, AVG, etc.)
- Identify FILTERS and CONDITIONS
- Identify the TIME PERIOD if present

STEP 2 - MAP TO SCHEMA:
- Find relevant tables in the provided schema
- Identify EXACT column names (respect case!)
- Verify data types
- If you don't know the exact format of a value (e.g., quarter), use LIKE with wildcard.
Example: quarter LIKE 'Q3%' instead of quarter = 'Q3'
- CRITICAL - ENTITY NAMES: When filtering by name (company_name, product_name, etc.), ALWAYS use ILIKE with wildcards.
  GOOD: WHERE company_name ILIKE '%TechVision%'
  BAD: WHERE company_name = 'TechVision'
  Database names often include suffixes (Inc, Corp, Labs, Ltd).
  Alternative: use company_id if available (e.g., company_id = 'techvision')
- CRITICAL - PERIOD FILTER / DOUBLE-COUNTING PREVENTION:
  The financials table contains BOTH period-level rows (Q1, Q2, Q3, Q4) AND full-year aggregate rows (period = 'FY').
  * For annual/total revenue queries: ALWAYS filter with period = 'FY' to get the pre-computed annual total. Do NOT use SUM() across all periods as this will double-count (giving 2x the real value).
  * For quarterly queries: filter by the specific period (e.g., period = 'Q1').
  * Only use SUM() when aggregating across different companies or fiscal_years, NOT across periods within the same company/year.
  * Example CORRECT query: SELECT revenue FROM financials WHERE company_name ILIKE '%TechVision%' AND fiscal_year = 2023 AND period = 'FY'
  * Example WRONG query: SELECT SUM(revenue) FROM financials WHERE company_name ILIKE '%TechVision%' AND fiscal_year = 2023  -- This sums FY + Q1+Q2+Q3+Q4 = 2x!
- Identify necessary JOINs

STEP 3 - BUILD THE QUERY:
- SELECT: columns to return
- FROM: main table
- JOIN: if multi-table
- WHERE: filters + tenant_id = '${initData.user_context.tenant_id}'
- GROUP BY: if aggregation
- ORDER BY: if sorting requested
- LIMIT: max 1000

STEP 4 - VERIFY:
- Is the query syntactically valid?
- Does it answer the original question?
- Do the column names exist in the schema?

=== SECURITY RULES ===
1. ALWAYS start with SELECT
2. ALWAYS include tenant_id in WHERE (use: tenant_id = 'default' OR tenant_id IS NULL for max coverage)
3. ALWAYS LIMIT (max 1000)
4. NEVER use DELETE, UPDATE, INSERT, DROP, TRUNCATE, ALTER, CREATE
5. NEVER use SQL comments (--)

=== STRICT JSON FORMAT ===
{
  "reasoning": {
    "entities_found": ["..."],
    "metrics_needed": ["..."],
    "filters_identified": ["..."],
    "tables_used": ["..."],
    "joins_needed": ["..."],
    "potential_issues": ["..."]
  },
  "sql": "SELECT ... FROM ... WHERE tenant_id = '<TENANT_ID>' LIMIT 1000",
  "explanation": "This query does X because Y",
  "confidence": 0.0-1.0
}`
    },
    {
      role: "user",
      content: `=== USER QUESTION ===
${initData.query}

=== AVAILABLE SCHEMA ===
${initData.schema_context}

=== CONTEXT ===
Tenant ID: ${initData.user_context.tenant_id}
Groups: ${JSON.stringify(initData.user_context.groups)}

Generate the SQL query with complete Chain-of-Thought reasoning.`
    }
  ],
  temperature: 0.1,
  max_tokens: 1000
};

return {
  json: {
    requestBody: requestBody,
    template_matched: false
  }
};

// Prepare Interpretation Request - Safe JSON Building
const aggregatorData = $node['Result Aggregator'].json;

const requestBody = {
  model: 'google/gemma-3-27b-it:free',
  messages: [
    {
      role: "system",
      content: "You are an expert financial analyst. Interpret the SQL results and answer the original question clearly and concisely. Always respond in the same language as the question. If the data is empty, explain why."
    },
    {
      role: "user",
      content: `Original question: ${aggregatorData.query}

Executed SQL query: ${aggregatorData.validated_sql}

Results (${aggregatorData.result_count} rows):
${aggregatorData.result_preview}`
    }
  ],
  temperature: 0.3,
  max_tokens: 800
};

return {
  json: {
    ...aggregatorData,
    requestBody: requestBody
  }
};

// Prepare SQL Repair Request - null-safe guard
const errorHandlerData = $json;
const repairContext = errorHandlerData.repair_context || {};

if (!repairContext.failed_sql) {
  return { json: { ...errorHandlerData, requestBody: {"model": "meta-llama/llama-3.3-70b-instruct:free", "messages": [{"role": "user", "content": "return empty JSON: {}"}], "max_tokens": 5}, skip_repair: true } };
}

const requestBody = {
  model: 'google/gemma-3-12b-it:free',
  messages: [
    { role: "system", content: "You are an expert SQL debugger. Fix the failed SQL query. Return JSON: {analysis, fix_applied, sql, confidence}" },
    { role: "user", content: "FAILED SQL:\n" + (repairContext.failed_sql || "N/A") + "\n\nERROR:\n" + (repairContext.error_message || "Unknown") + "\n\nSCHEMA:\n" + (repairContext.schema_context || "N/A") + "\n\nQUESTION:\n" + (repairContext.original_question || "N/A") }
  ],
  temperature: 0.1,
  max_tokens: 800
};

return { json: { ...errorHandlerData, requestBody } };

// GitHub Error Logger for quantitative
const errorData = $input.first().json;
const timestamp = new Date().toISOString();
const questionId = errorData.question_id || errorData.trace_id || 'q-' + Date.now();
const errorType = errorData.error_type || errorData.error_code || 'UNKNOWN';
const pipeline = 'quantitative';

const logEntry = {
  timestamp: timestamp,
  pipeline: pipeline,
  question_id: questionId,
  error_type: errorType,
  error_message: (errorData.error || errorData.message || 'No message').slice(0, 500),
  input: {
    query: (errorData.query || errorData.original_query || '').slice(0, 300),
    tenant_id: errorData.tenant_id || 'benchmark'
  },
  partial_response: errorData.partial_response || errorData.response || null,
  n8n_context: {
    workflow_id: $workflow.id,
    workflow_name: $workflow.name,
    execution_id: $execution.id
  },
  performance: {
    latency_ms: errorData.latency_ms || 0,
    http_status: errorData.http_status || null
  }
};

return [{ json: logEntry }];

// SQL Execution Logger
const input = $input.first().json;

const log = {
  timestamp: new Date().toISOString(),
  pipeline: 'quantitative',
  step: 'sql_execution',
  sql: (input.validated_sql || input.sql || input.sql_executed || '').slice(0, 500),
  validation_status: input.validation_status || input.metadata?.validation_status || 'UNKNOWN',
  result_count: input.result_count || 0,
  null_aggregation: input.null_aggregation || false,
  error: input.sql_error || null
};

return [{ json: { ...input, _sql_log: log } }];

// Question Type Classifier — Routes between SQL and Context Reasoning
const initData = $input.first().json;
const query = initData.query || '';

// Detect Phase 2 context-rich questions (finqa, tatqa, convfinqa format)
// These questions embed financial context and tables in the question text
const hasContextMarker = query.includes('Context:') && query.includes('Question:');
const hasTableData = /\|[^|]+\|[^|]+\|/.test(query);
const isLongWithContext = (hasContextMarker || hasTableData) && query.length > 500;
// Also detect 'Please answer the given financial question' pattern
const isFinancialContext = query.toLowerCase().includes('please answer the given financial question');

const isContextQuestion = isLongWithContext || isFinancialContext;

if (isContextQuestion) {
  // Extract the actual question and context from the composite string
  let extractedQuestion = query;
  let extractedContext = '';

  const contextMatch = query.match(/Context:\s*([\s\S]+?)(?=\nQuestion:|$)/);
  const questionMatch = query.match(/Question:\s*([\s\S]+?)(?:\nAnswer:|$)/);

  if (contextMatch) extractedContext = contextMatch[1].trim();
  if (questionMatch) extractedQuestion = questionMatch[1].trim();

  return [{
    json: {
      ...initData,
      question_type: 'context_reasoning',
      extracted_question: extractedQuestion,
      extracted_context: extractedContext.substring(0, 8000),
      original_query: query
    }
  }];
} else {
  return [{
    json: {
      ...initData,
      question_type: 'sql_query'
    }
  }];
}

// Build LLM request for direct context-based financial reasoning
// Phase 2 questions (finqa, tatqa, convfinqa) embed context + tables in the question
const data = $input.first().json;

const requestBody = {
  model: 'meta-llama/llama-3.3-70b-instruct:free',
  messages: [
    {
      role: 'system',
      content: 'You are an expert financial analyst. Answer the question based ONLY on the provided context and data tables.\n\n'
        + 'RULES:\n'
        + '1. Use ONLY the data from the context — never invent numbers\n'
        + '2. Show your calculation steps briefly\n'
        + '3. For percentages, calculate precisely (e.g., 0.14464)\n'
        + '4. For currency values, give the exact number (e.g., 94.0)\n'
        + '5. Keep your answer concise — give the numerical answer first, then a brief explanation\n'
        + '6. If the answer is a list, separate items with newlines\n'
        + '7. Match the format expected by the question\n'
        + '8. If a table is provided, read the exact values from it\n'
        + 'IMPORTANT: Start your response with the direct answer (number, percentage, or text).'
    },
    {
      role: 'user',
      content: data.extracted_context
        ? 'Context:\n' + data.extracted_context + '\n\nQuestion: ' + data.extracted_question
        : data.original_query || data.query
    }
  ],
  temperature: 0.1,
  max_tokens: 500
};

return [{
  json: {
    ...data,
    requestBody: requestBody
  }
}];

// Format context reasoning response into standard pipeline output
const data = $input.first().json;
let interpretation = '';

if (data.choices && data.choices[0] && data.choices[0].message) {
  interpretation = data.choices[0].message.content;
} else if (data.error) {
  interpretation = 'Context reasoning failed: ' + 
    (typeof data.error === 'object' ? JSON.stringify(data.error) : String(data.error));
} else {
  interpretation = 'No response from LLM';
}

// Get init data from upstream
let initData = {};
try {
  initData = $node['Question Type Classifier'].json || {};
} catch(e) {
  try { initData = $node['Init & ACL'].json || {}; } catch(e2) { initData = {}; }
}

return [{
  json: {
    status: interpretation.includes('failed') ? 'ERROR' : 'SUCCESS',
    trace_id: initData.trace_id || '',
    query: initData.extracted_question || initData.query || '',
    sql_executed: 'N/A (context-based reasoning)',
    result_count: 1,
    interpretation: interpretation,
    raw_results: [],
    null_aggregation: false,
    metadata: {
      validation_status: 'CONTEXT_REASONING',
      question_type: 'context_reasoning',
      timestamp: new Date().toISOString(),
      engine: 'QUANTITATIVE'
    }
  }
}];
